use "@Engine/Core/LazyBehaviors/LazyBehavior.lsx" as LazyBehaviorMod

export const Transform : base(LazyBehaviorMod.LazyBehavior) = {
    position = {0, 0, 0}

    Update = fn()
        -- Transform-specific update code.
    end
}

export const Transform : base(LazyBehaviorMod.LazyBehavior) = {
    constructor = fn(parent)
        self.lazyVars = {
            parent = {type = "gameObject", visible = false, value = parent}
            position = {type = "vec3", visible = true, value = {0, 0, 0}}
        }
    end
}

export const Spinner : base(LazyBehaviorMod.LazyBehavior) = {
    Update = fn()
        self.angle = self.angle + 1.0
    end
}

